// Yandex Direct API v5 proxy.
// docs: https://yandex.ru/dev/direct/doc/dg/concepts/about.html
//
// POST /webhook/yadirect with body { action, ...params }
//
// Supported actions (минимум для управления кампанией):
//
//   { action: 'clients.get' }                                    — info об аккаунте (валюта, тип, login)
//
//   { action: 'campaigns.get', filters? }                        — список кампаний
//   { action: 'campaigns.add', campaigns: [...] }                — создать (рекомендую CreateInDraft)
//   { action: 'campaigns.suspend', ids: [...] }                  — поставить на паузу
//   { action: 'campaigns.resume',  ids: [...] }
//   { action: 'campaigns.delete',  ids: [...] }
//
//   { action: 'adgroups.get', filters? }
//   { action: 'adgroups.add', adGroups: [...] }
//
//   { action: 'ads.get', filters? }
//   { action: 'ads.add', ads: [...] }
//   { action: 'ads.moderate', ids: [...] }                        — отправить на модерацию
//
//   { action: 'keywords.add', keywords: [...] }                   — ключевые фразы
//   { action: 'keywords.suspend' / 'resume' / 'delete', ids: [...] }
//
//   { action: 'changes.checkDictionaries' } / 'changes.check'     — проверка инкр.апдейтов
//
//   { action: 'raw', service, method, params }                    — на всякий случай: прокинуть как есть
//
//   { action: 'reports.get', body }                                — отчёты (другой эндпоинт, см. ниже)
//
// Env required:
//   YANDEX_DIRECT_TOKEN      — OAuth токен (Bearer)
//   YANDEX_DIRECT_LOGIN      — Client-Login (логин рекламодателя)
//   YANDEX_DIRECT_SANDBOX    — '1' = sandbox, '0' / unset = prod

const raw = $input.first().json;
const body = (raw.body && raw.body.action) ? raw.body : raw;
const action = String(body.action || '').trim();
if (!action) {
  return [{ json: { _skip: true, error: 'no action', statusCode: 400 } }];
}

const token = $env.YANDEX_DIRECT_TOKEN;
if (!token) {
  return [{ json: { _skip: true, error: 'YANDEX_DIRECT_TOKEN not set on server', statusCode: 500 } }];
}
const login = $env.YANDEX_DIRECT_LOGIN || '';
const sandbox = String($env.YANDEX_DIRECT_SANDBOX || '0') === '1';

const apiBase     = sandbox ? 'https://api-sandbox.direct.yandex.com/json/v5' : 'https://api.direct.yandex.com/json/v5';
const reportsBase = sandbox ? 'https://api-sandbox.direct.yandex.com/v5/reports' : 'https://api.direct.yandex.com/v5/reports';

let service, method, params;
let url, payload, isReport = false;

function split(a) {
  const idx = a.indexOf('.');
  if (idx < 0) return [a, 'get'];
  return [a.slice(0, idx), a.slice(idx + 1)];
}

if (action === 'raw') {
  service = String(body.service || '').trim();
  method  = String(body.method  || 'get').trim();
  params  = body.params || {};
  if (!service) return [{ json: { _skip: true, error: 'service required for raw', statusCode: 400 } }];
} else if (action === 'reports.get') {
  isReport = true;
  if (!body.body) return [{ json: { _skip: true, error: 'reports.get requires body (XML или JSON отчёта)', statusCode: 400 } }];
  payload = body.body;
} else {
  [service, method] = split(action);
  // map action → params
  switch (action) {
    case 'clients.get':
      params = { FieldNames: body.FieldNames || ['Login','ClientId','Currency','Type','CountryId','Phone','Email','VatRate','SmsSettings'] };
      break;
    case 'campaigns.get':
      params = {
        SelectionCriteria: body.filters || {},
        FieldNames: body.FieldNames || ['Id','Name','Status','State','Type','StartDate','EndDate','DailyBudget','Currency','Funds'],
        TextCampaignFieldNames: body.TextCampaignFieldNames
      };
      Object.keys(params).forEach(k => params[k] === undefined && delete params[k]);
      break;
    case 'campaigns.add':
      if (!Array.isArray(body.campaigns) || !body.campaigns.length) return [{ json: { _skip: true, error: 'campaigns array required', statusCode: 400 } }];
      params = { Campaigns: body.campaigns };
      break;
    case 'campaigns.suspend':
    case 'campaigns.resume':
    case 'campaigns.delete':
    case 'campaigns.archive':
    case 'campaigns.unarchive':
      if (!Array.isArray(body.ids) || !body.ids.length) return [{ json: { _skip: true, error: 'ids array required', statusCode: 400 } }];
      params = { SelectionCriteria: { Ids: body.ids } };
      break;
    case 'adgroups.get':
      params = {
        SelectionCriteria: body.filters || {},
        FieldNames: body.FieldNames || ['Id','Name','CampaignId','Status','Type','RegionIds','NegativeKeywords','TrackingParams']
      };
      break;
    case 'adgroups.add':
      if (!Array.isArray(body.adGroups) || !body.adGroups.length) return [{ json: { _skip: true, error: 'adGroups array required', statusCode: 400 } }];
      params = { AdGroups: body.adGroups };
      break;
    case 'ads.get':
      params = {
        SelectionCriteria: body.filters || {},
        FieldNames: body.FieldNames || ['Id','State','Status','AdGroupId','CampaignId','Type'],
        TextAdFieldNames: body.TextAdFieldNames || ['Title','Title2','Text','Href','VCardId','SitelinkSetId']
      };
      break;
    case 'ads.add':
      if (!Array.isArray(body.ads) || !body.ads.length) return [{ json: { _skip: true, error: 'ads array required', statusCode: 400 } }];
      params = { Ads: body.ads };
      break;
    case 'ads.moderate':
    case 'ads.suspend':
    case 'ads.resume':
    case 'ads.delete':
      if (!Array.isArray(body.ids) || !body.ids.length) return [{ json: { _skip: true, error: 'ids array required', statusCode: 400 } }];
      params = { SelectionCriteria: { Ids: body.ids } };
      break;
    case 'keywords.add':
      if (!Array.isArray(body.keywords) || !body.keywords.length) return [{ json: { _skip: true, error: 'keywords array required', statusCode: 400 } }];
      params = { Keywords: body.keywords };
      break;
    case 'keywords.suspend':
    case 'keywords.resume':
    case 'keywords.delete':
      if (!Array.isArray(body.ids) || !body.ids.length) return [{ json: { _skip: true, error: 'ids array required', statusCode: 400 } }];
      params = { SelectionCriteria: { Ids: body.ids } };
      break;
    case 'changes.checkDictionaries':
      params = {};
      break;
    case 'changes.check':
      if (!body.timestamp) return [{ json: { _skip: true, error: 'timestamp required (UTC, RFC 3339)', statusCode: 400 } }];
      params = { Timestamp: body.timestamp, FieldNames: body.FieldNames || ['Timestamp','CampaignsChanges','NotFoundCampaignIds'] };
      break;
    default:
      return [{ json: { _skip: true, error: 'unknown action: ' + action + '. Use action=raw with {service, method, params} for arbitrary calls', statusCode: 400 } }];
  }
}

if (isReport) {
  url = reportsBase;
} else {
  url = apiBase + '/' + service;
  payload = { method, params };
}

return [{ json: { _skip: false, action, token, login, sandbox, url, isReport, payload } }];

const res = $input.first().json;
const ctx = $('Route').first().json;
const statusCode = res.statusCode || 200;
const headers = res.headers || {};
const raw = res.body != null ? res.body : res;

let parsed = raw;
if (typeof raw === 'string') {
  try { parsed = JSON.parse(raw); } catch(e) { parsed = { raw }; }
}

// Direct API возвращает {result: ...} или {error: ...} в JSON, статус всегда 200/4xx/5xx
const direct = parsed && typeof parsed === 'object' ? parsed : {};
const errPayload = direct.error;
if (errPayload) {
  return [{ json: {
    ok: false,
    statusCode: 502,
    error_code: errPayload.error_code,
    error: errPayload.error_string || errPayload.error_detail,
    detail: errPayload.error_detail,
    request_id: errPayload.request_id,
    units: headers['units'] || headers['Units']
  } }];
}
if (statusCode >= 400) {
  return [{ json: { ok: false, statusCode, error: 'http_' + statusCode, raw: parsed } }];
}

return [{ json: {
  ok: true,
  action: ctx.action,
  sandbox: ctx.sandbox,
  result: direct.result || direct,
  units: headers['units'] || headers['Units']
} }];
